svg.script:
(function () {
  var svg          = document.getElementById('root');
  var dataLayerEl  = document.getElementById('data-layer');
  var ringLayer    = document.getElementById('ring-layer');
  var edgeLayer    = document.getElementById('edge-layer');
  var nodeLayer    = document.getElementById('node-layer');

  /* ¬ß2 isDark before all build code */
  var isDark = false;

  /* ‚îÄ‚îÄ DATA ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
     cluster: 1=Frontend 2=Backend 3=Data 4=Infra 5=Auth
     Nodes ordered by cluster so they group together on the ring.        */
  var nodes = [
    /* Frontend */
    { id:'web-app',   label:'Web App',   cluster:1 },
    { id:'mobile',    label:'Mobile',    cluster:1 },
    { id:'cdn',       label:'CDN',       cluster:1 },
    /* Backend */
    { id:'api-gw',    label:'API GW',    cluster:2 },
    { id:'user-svc',  label:'User Svc',  cluster:2 },
    { id:'order-svc', label:'Order Svc', cluster:2 },
    { id:'notify',    label:'Notify',    cluster:2 },
    /* Data */
    { id:'postgres',  label:'Postgres',  cluster:3 },
    { id:'redis',     label:'Redis',     cluster:3 },
    { id:'kafka',     label:'Kafka',     cluster:3 },
    { id:'analytics', label:'Analytics', cluster:3 },
    /* Infra */
    { id:'k8s',       label:'K8s',       cluster:4 },
    { id:'monitor',   label:'Monitor',   cluster:4 },
    { id:'cicd',      label:'CI/CD',     cluster:4 },
    /* Auth */
    { id:'auth-svc',  label:'Auth Svc',  cluster:5 },
    { id:'oauth',     label:'OAuth',     cluster:5 },
  ];

  var edges = [
    { a:'web-app',   b:'cdn'       },
    { a:'mobile',    b:'cdn'       },
    { a:'cdn',       b:'api-gw'    },
    { a:'web-app',   b:'api-gw'    },
    { a:'api-gw',    b:'user-svc'  },
    { a:'api-gw',    b:'order-svc' },
    { a:'order-svc', b:'notify'    },
    { a:'user-svc',  b:'notify'    },
    { a:'user-svc',  b:'postgres'  },
    { a:'order-svc', b:'postgres'  },
    { a:'user-svc',  b:'redis'     },
    { a:'order-svc', b:'redis'     },
    { a:'notify',    b:'kafka'     },
    { a:'api-gw',    b:'kafka'     },
    { a:'kafka',     b:'analytics' },
    { a:'postgres',  b:'analytics' },
    { a:'auth-svc',  b:'api-gw'    },
    { a:'auth-svc',  b:'oauth'     },
    { a:'oauth',     b:'k8s'       },
    { a:'k8s',       b:'api-gw'    },
    { a:'k8s',       b:'postgres'  },
    { a:'k8s',       b:'monitor'   },
    { a:'cicd',      b:'k8s'       },
    { a:'monitor',   b:'analytics' },
  ];

  /* ‚îÄ‚îÄ BUILD LOOKUP + DEGREE ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  var byId = {};
  nodes.forEach(function(n) { byId[n.id] = n; n.neighbours = []; n.edgeEls = []; });
  edges.forEach(function(e) {
    byId[e.a].neighbours.push(e.b);
    byId[e.b].neighbours.push(e.a);
  });

  /* radius encodes degree */
  nodes.forEach(function(n) {
    n.r = 11 + Math.min(n.neighbours.length - 1, 5) * 2.2;
  });

  /* ‚îÄ‚îÄ CIRCULAR LAYOUT ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
     Plot area: left=68 right=850 top=100 bottom=500
     Centre the circle within the plot area.
     Gap of ~14¬∞ between each cluster group.                            */
  var plotL = 68, plotR = 850, plotT = 100, plotB = 500;
  var cx = (plotL + plotR) / 2;   /* 459 */
  var cy = (plotT + plotB) / 2;   /* 300 */
  var ringR = 185;                 /* radius of the node ring */
  var labelR = ringR + 26;        /* label offset from centre */

  var N = nodes.length;           /* 16 */
  var gapDeg = 14;                /* degrees of gap between clusters */

  /* count clusters */
  var clusterCounts = {};
  nodes.forEach(function(n) { clusterCounts[n.cluster] = (clusterCounts[n.cluster] || 0) + 1; });
  var clusterIds = [1, 2, 3, 4, 5];
  var numClusters = clusterIds.length;

  /* total arc available for nodes = 360 - gaps */
  var totalGapDeg = numClusters * gapDeg;
  var nodeArcDeg  = 360 - totalGapDeg;
  /* degrees per node slot */
  var degPerNode  = nodeArcDeg / N;

  /* assign angle to each node, leaving a gap before each new cluster */
  var angleDeg = -90 - (nodeArcDeg / 2);  /* start at top, centred */
  var prevCluster = null;
  nodes.forEach(function(n) {
    if (prevCluster !== null && n.cluster !== prevCluster) {
      angleDeg += gapDeg;
    }
    n.angle = angleDeg + degPerNode / 2;
    angleDeg += degPerNode;
    prevCluster = n.cluster;

    var rad = n.angle * Math.PI / 180;
    n.x = cx + ringR * Math.cos(rad);
    n.y = cy + ringR * Math.sin(rad);

    /* label position ‚Äî pushed outward, anchor based on side */
    var lx = cx + labelR * Math.cos(rad);
    var ly = cy + labelR * Math.sin(rad);
    var anchor = (Math.cos(rad) > 0.1) ? 'start' : (Math.cos(rad) < -0.1) ? 'end' : 'middle';
    n.lx = lx; n.ly = ly; n.anchor = anchor;
  });

  /* ‚îÄ‚îÄ STAGGER ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  var totalEls  = edges.length + nodes.length;
  var stagger   = Math.min(0.25, 1.0 / totalEls);
  var lastDelay = (totalEls - 1) * stagger;
  var readyDelay = (lastDelay + 0.8 + 0.1) * 1000;

  /* ‚îÄ‚îÄ DRAW RING GUIDE ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  var ringGuide = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
  ringGuide.setAttribute('cx', cx);
  ringGuide.setAttribute('cy', cy);
  ringGuide.setAttribute('r',  ringR);
  ringGuide.setAttribute('class', 'ring-guide');
  ringLayer.appendChild(ringGuide);

  /* ‚îÄ‚îÄ BUILD EDGES ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  edges.forEach(function(e, i) {
    var na = byId[e.a], nb = byId[e.b];

    /* quadratic bezier: control point pulled toward centre by a pull factor.
       Pull = 0.35 means control point is 35% of the way from midpoint to centre. */
    var pull = 0.42;
    var mx = (na.x + nb.x) / 2;
    var my = (na.y + nb.y) / 2;
    var qx = mx + (cx - mx) * pull;
    var qy = my + (cy - my) * pull;

    var path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    path.setAttribute('d', 'M' + na.x + ',' + na.y + ' Q' + qx + ',' + qy + ' ' + nb.x + ',' + nb.y);
    path.setAttribute('class', 'edge stroke-' + na.cluster);
    path.setAttribute('data-a', e.a);
    path.setAttribute('data-b', e.b);
    path.style.animationDelay = (i * stagger) + 's';
    edgeLayer.appendChild(path);

    na.edgeEls.push(path);
    nb.edgeEls.push(path);
  });

  /* ‚îÄ‚îÄ BUILD NODES ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  nodes.forEach(function(n, i) {
    var ng = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    ng.setAttribute('class', 'node-g');
    ng.setAttribute('id', 'ng-' + n.id);
    ng.style.animationDelay = (edges.length * stagger + i * stagger) + 's';

    var circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    circle.setAttribute('cx', n.x); circle.setAttribute('cy', n.y);
    circle.setAttribute('r',  n.r);
    circle.setAttribute('class', 'node-circle series-' + n.cluster + ' stroke-' + n.cluster);

    var lbl = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    lbl.setAttribute('x', n.lx); lbl.setAttribute('y', n.ly + 3.5);
    lbl.setAttribute('text-anchor', n.anchor);
    lbl.setAttribute('class', 'node-lbl');
    lbl.textContent = n.label;

    ng.appendChild(circle);
    ng.appendChild(lbl);
    nodeLayer.appendChild(ng);
    n._ng = ng;
  });

  /* ‚îÄ‚îÄ ¬ß3 A1 ANIMATION ‚Äî animationend per element, .visible provides resting opacity ‚îÄ‚îÄ */
  Array.prototype.forEach.call(edgeLayer.querySelectorAll('.edge'), function(el) {
    el.style.animation = 'edgeFadeIn 0.8s ease-out ' + el.style.animationDelay;
    el.addEventListener('animationend', function() {
      el.style.animation = 'none';
      el.classList.add('visible');
    }, { once: true });
  });
  Array.prototype.forEach.call(nodeLayer.querySelectorAll('.node-g'), function(el) {
    el.style.animation = 'nodeFadeIn 0.8s ease-out ' + el.style.animationDelay;
    el.addEventListener('animationend', function() {
      el.style.animation = 'none';
      el.classList.add('visible');
    }, { once: true });
  });

  setTimeout(function() {
    dataLayerEl.classList.add('ready');
  }, readyDelay);

  /* ‚îÄ‚îÄ ¬ß5 TOOLTIP ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  var tip    = document.getElementById('tip');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');

  function showTip(nx, ny, nodeR, valTxt, lblTxt) {
    tipVal.textContent = valTxt;
    tipLbl.textContent = lblTxt;
    var pad = 20, bh = 38, rx = 9, tw = 8, tail = 10;
    var hw  = Math.max(tipVal.getBBox().width, tipLbl.getBBox().width) / 2 + pad / 2;
    var tx  = Math.max(hw + 8, Math.min(nx, plotR - hw - 8));
    var anchorY = ny - nodeR;
    var above = (anchorY - tail - bh - 4) >= plotT;
    var bT, bB;
    if (above) { bB = anchorY - tail; bT = bB - bh; }
    else        { bT = ny + nodeR + tail; bB = bT + bh; }

    tipBg.setAttribute('x', tx - hw); tipBg.setAttribute('y', bT);
    tipBg.setAttribute('width', hw * 2); tipBg.setAttribute('height', bh);

    var tipAnchorY = above ? anchorY : ny + nodeR;
    if (above) {
      tipBdr.setAttribute('d',
        'M'+(tx+tw)+','+bB+' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+
        ' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+' L'+(tx-tw)+','+bB);
      tipTip.setAttribute('d', 'M'+(tx-tw)+','+bB+' L'+tx+','+(tipAnchorY-2)+' L'+(tx+tw)+','+bB);
    } else {
      tipBdr.setAttribute('d',
        'M'+(tx-tw)+','+bT+' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+
        ' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+' L'+(tx+tw)+','+bT);
      tipTip.setAttribute('d', 'M'+(tx+tw)+','+bT+' L'+tx+','+(tipAnchorY+2)+' L'+(tx-tw)+','+bT);
    }
    tipVal.setAttribute('x', tx); tipVal.setAttribute('y', bT + bh * 0.32);
    tipLbl.setAttribute('x', tx); tipLbl.setAttribute('y', bT + bh * 0.72);
    tip.style.opacity = '1';
  }

  function hideTip() {
    tip.style.opacity = '';
  }

  /* ‚îÄ‚îÄ ¬ß4 HOVER ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
     Nodes sit on a ring with clear gaps ‚Üí element-level mouseleave.
     Stale-clear on every mouseenter is non-optional.                   */
  var allNodeGs = Array.prototype.slice.call(nodeLayer.querySelectorAll('.node-g'));
  var allEdges  = Array.prototype.slice.call(edgeLayer.querySelectorAll('.edge'));
  var clusterNames = ['','Frontend','Backend','Data','Infra','Auth'];

  nodes.forEach(function(n) {
    var ng = n._ng;
    ng.addEventListener('mouseenter', function() {
      if (!dataLayerEl.classList.contains('ready')) return;

      /* clear stale */
      allNodeGs.forEach(function(el) { el.classList.remove('hovered'); el.classList.remove('connected'); });
      allEdges.forEach(function(el)  { el.classList.remove('connected'); });
      dataLayerEl.classList.add('hovering');

      ng.classList.add('hovered');

      /* mark neighbours */
      n.neighbours.forEach(function(nid) {
        var nng = document.getElementById('ng-' + nid);
        if (nng) nng.classList.add('connected');
      });

      /* mark connecting edges */
      n.edgeEls.forEach(function(el) { el.classList.add('connected'); });

      var deg = n.neighbours.length;
      showTip(n.x, n.y, n.r,
        n.label,
        clusterNames[n.cluster] + ' \u00b7 ' + deg + ' connection' + (deg !== 1 ? 's' : ''));
    });

    ng.addEventListener('mouseleave', function() {
      allNodeGs.forEach(function(el) { el.classList.remove('hovered'); el.classList.remove('connected'); });
      allEdges.forEach(function(el)  { el.classList.remove('connected'); });
      dataLayerEl.classList.remove('hovering');
      hideTip();
    });
  });

  /* ‚îÄ‚îÄ PRINT TOGGLE ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print'; }
  });

  /* ‚îÄ‚îÄ ¬ß2 DARK MODE ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ */
  function setMode(wantDark) {
    if (wantDark === isDark) return;
    isDark = wantDark;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx','52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx','16');
      if (lbl)   lbl.textContent = 'Dark';
    }
  }

  document.getElementById('dark-toggle').addEventListener('click', function() { setMode(!isDark); });
  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });
  setMode(window.location.href.indexOf('theme=dark') !== -1);
})();
